@Page
@Composable
fun LoginScreen(){

    val scope = rememberCoroutineScope()
    val context = rememberPageContext()
    var errorText by remember { mutableStateOf(" ") }

    Box(
        modifier = Modifier.fillMaxSize(),
        contentAlignment = Alignment.Center
    ) {
        Column(
            modifier = Modifier
                .padding(leftRight = 50.px, top = 80.px, bottom = 24.px)
                .backgroundColor(color = Color.lightgray),
            verticalArrangement = Arrangement.Center,
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            H1(
                attrs = Modifier
                    .color(Colors.SteelBlue)
                    .fontSize(32.px)
                    .fontWeight(FontWeight.ExtraBold)
                    .textAlign(TextAlign.Center)
                    .margin(bottom = 50.px)
                    .toAttrs()
            ) {
                Text("EPE ACADEMY")
            }
            Input(
                type = InputType.Text,
                attrs = LoginInputStyle.toModifier()
                    .id(Id.USERNAME_INPUT)
                    .margin(bottom = 12.px)
                    .width(350.px)
                    .height(54.px)
                    .backgroundColor(Colors.White)
                    .outline(
                        width = 0.px,
                        style = LineStyle.None,
                        color = Colors.Transparent
                    )
                    .toAttrs {
                        attr("placeholder", "Username")
                    }
            )
            Input(
                type = InputType.Password,
                attrs = LoginInputStyle.toModifier()
                    .id(Id.PASSWORD_INPUT)
                    .backgroundColor(Colors.White)
                    .margin(bottom = 12.px)
                    .width(350.px)
                    .height(54.px)
                    .outline(
                        width = 0.px,
                        style = LineStyle.None,
                        color = Colors.Transparent
                    )
                    .toAttrs {
                        attr("placeholder", "Password")
                    }
            )
            Button(
                attrs = LoginInputStyle.toModifier()
                    .margin(bottom = 24.px)
                    .width(350.px)
                    .height(54.px)
                    .borderRadius(r = 4.px)
                    .cursor(Cursor.Pointer)
                    .outline(
                        width = 0.px,
                        style = LineStyle.None,
                        color = Colors.Transparent
                    )
                    .backgroundColor(color = Colors.SteelBlue)
                    .color(color = Colors.White)
                    .fontWeight(FontWeight.Medium)
                    .fontSize(16.px)
                    .onClick {
                        scope.launch {
                            val username =
                                (document.getElementById(Id.USERNAME_INPUT) as HTMLInputElement).value
                            val password =
                                (document.getElementById(Id.PASSWORD_INPUT) as HTMLInputElement).value
                            if (username.isNotEmpty() && password.isNotEmpty()) {
                                val user = checkUserExistence(
                                    user = User(
                                        username = username,
                                        password = password
                                    )
                                )
                                if (user != null) {
                                    rememberLoggedIn(remember = true, user = user)
                                    context.router.navigateTo(Screen.AdminHome.route)
                                } else {
                                    errorText = "User doesn't exist !!"
                                    delay(3000)
                                    errorText = " "
                                }
                            } else {
                                errorText = "Input fields are empty!"
                                delay(3000)
                                errorText = " "
                            }
                        }
                    }
                    .toAttrs()
            ) {
                SpanText("Sing in")
            }
            SpanText(
                text = errorText,
                modifier = Modifier
                    .width(350.px)
                    .color(Colors.Red)
                    .textAlign(TextAlign.Center)
            )
        }
    }
}

private fun rememberLoggedIn(
    remember: Boolean,
    user: UserWithoutPassword? = null
) {
    localStorage["remember"] = remember.toString()
    if (user != null) {
        localStorage["userId"] = user.id
        localStorage["username"] = user.username
    }
}